﻿@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <nav class="wizard-progress" aria-label="Application progress">
                    <ol class="wizard-steps">
                        @foreach (var (url, label, step) in Steps)
                        {
                            var css = step == CurrentStep ? "active"
                                : Progress?.CompletedSteps.Contains(step) == true ? "completed"
                                : "";

                            <li class="wizard-step @css">
                                <a href="@url">
                                    <span class="step-number">@step</span>
                                    <span class="step-label">@label</span>
                                </a>
                            </li>
                        }
                    </ol>
                    <span class="step-indicator">Step @CurrentStep of @Steps.Length</span>
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }

    private static readonly (string Url, string Label, int Step)[] Steps =
    [
        ("/apply/personal-info", "Personal Info", 1),
        ("/apply/experience", "Experience", 2),
        ("/apply/references", "References", 3),
        ("/apply/review", "Review", 4)
    ];

    private bool IsWizardPage =>
        Nav.ToAbsoluteUri(Nav.Uri).AbsolutePath.StartsWith("/apply/", StringComparison.OrdinalIgnoreCase);

    private int CurrentStep => Nav.ToAbsoluteUri(Nav.Uri).AbsolutePath switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 0
    };
}

