@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState State
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Personal Information</PageTitle>

<h1>Personal Information</h1>

<div class="mb-3">
    <label for="name" class="form-label">Full Name</label>
    <input id="name" class="form-control" @bind="State.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email Address</label>
    <input id="email" type="email" class="form-control" @bind="State.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    [CascadingParameter]
    private WizardProgress? Progress { get; set; }

    private async Task Next()
    {
        if (Progress is not null)
        {
            Progress.CompletedSteps.Add(1);
            await ProgressSource.NotifyChangedAsync(Progress);
        }
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState State
@inject CascadingValueSource<WizardProgress> ProgressSource
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>

<h1>Experience</h1>

@for (var i = 0; i < State.Experience.Count; i++)
{
    var index = i;
    var entry = State.Experience[index];

    <fieldset class="border rounded p-3 mb-3">
        <legend class="w-auto px-2 fs-6">Position @(index + 1)</legend>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="entry.Company" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="entry.Title" />
            </div>
        </div>

        <div class="row mb-2">
            <div class="col-md-5">
                <label class="form-label">Start Date</label>
                <input class="form-control" @bind="entry.StartDate" placeholder="e.g. Jan 2020" />
            </div>
            <div class="col-md-5">
                <label class="form-label">End Date</label>
                <input class="form-control" @bind="entry.EndDate" placeholder="e.g. Present" />
            </div>
            <div class="col-md-2 d-flex align-items-end">
                @if (State.Experience.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => Remove(index)">Remove</button>
                }
            </div>
        </div>
    </fieldset>
}

<button class="btn btn-outline-secondary mb-3" @onclick="Add">+ Add Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

