                    <tr>
                        <td>@NoneIfEmpty(e.Company)</td>
                        <td>@NoneIfEmpty(e.Title)</td>
                        <td>@NoneIfEmpty(e.StartDate)</td>
                        <td>@NoneIfEmpty(e.EndDate)</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    <a href="/apply/experience" class="btn btn-sm btn-outline-secondary">Edit</a>
</section>

<section class="mb-4">
    <h4>References</h4>
    @if (State.References.Count == 0)
    {
        <p class="text-muted">No entries.</p>
    }
    else
    {
        <table class="table table-sm">
            <thead>
                <tr>
                    <th>Name</th>
                    <th>Relationship</th>
                    <th>Email</th>
                    <th>Phone</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var r in State.References)
                {
                    <tr>
                        <td>@NoneIfEmpty(r.Name)</td>
                        <td>@NoneIfEmpty(r.Relationship)</td>
                        <td>@NoneIfEmpty(r.Email)</td>
                        <td>@NoneIfEmpty(r.Phone)</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    <a href="/apply/references" class="btn btn-sm btn-outline-secondary">Edit</a>
</section>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private bool submitted;

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        // Placeholder — wire up actual submission logic here.
        submitted = true;
    }

    private static string NoneIfEmpty(string? value) =>
        string.IsNullOrWhiteSpace(value) ? "—" : value;
}

